  "inlineSchema": "// Schema isolado do módulo de estoque\n// Seguindo premissas: módulos plugáveis, totalmente isolados, multi-tenant\n\ngenerator estoqueClient {\n  provider      = \"prisma-client-js\"\n  output        = \"../src/generated/estoque-client\"\n  binaryTargets = [\"native\", \"linux-musl\"]\n}\n\ndatasource estoqueDb {\n  provider     = \"mysql\"\n  url          = env(\"ESTOQUE_DATABASE_URL\")\n  relationMode = \"prisma\" // Importante para MySQL\n}\n\n// ===== TABELAS DO MÓDULO DE ESTOQUE =====\n\nmodel EstoqueLocalizacao {\n  id         String   @id @default(uuid())\n  codigo     String   @unique // A1-01-B-02-03 (endereçamento hierárquico)\n  deposito   String // Depósito principal\n  corredor   String? // Corredor específico\n  prateleira String? // Prateleira\n  nivel      String? // Nível da prateleira\n  posicao    String? // Posição específica\n  descricao  String? // Descrição adicional\n  capacidade Decimal? // Capacidade em unidades\n  ativo      Boolean  @default(true)\n\n  // Multi-tenant obrigatório (isolamento por loja)\n  lojaId String\n\n  // Relacionamentos\n  estoques EstoqueItem[]\n\n  // Timestamps para auditoria\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Índices obrigatórios para performance\n  @@index([lojaId])\n  @@index([codigo, lojaId])\n  @@index([deposito, lojaId])\n  @@map(\"estoque_localizacoes\")\n}\n\nmodel EstoqueItem {\n  id String @id @default(uuid())\n\n  // FK para módulo de insumos (integração nativa com cadastro existente)\n  insumoId String // Referência externa para evitar duplicação\n\n  // FK para localização (interna)\n  localizacaoId String\n  localizacao   EstoqueLocalizacao @relation(fields: [localizacaoId], references: [id])\n\n  // Quantidades (controle visível conforme premissas)\n  quantidadeAtual     Decimal  @default(0) // Quantidade atual em estoque\n  quantidadeReservada Decimal  @default(0) // Quantidade reservada para orçamentos\n  estoqueMinimo       Decimal  @default(0) // Estoque mínimo para alertas\n  estoqueMaximo       Decimal? // Estoque máximo (opcional)\n\n  // Multi-tenant obrigatório (isolamento por loja)\n  lojaId String\n\n  // Relacionamentos\n  movimentacoes EstoqueMovimentacao[]\n  lotes         EstoqueLote[]\n  sobras        EstoqueSobra[]\n\n  // Timestamps para auditoria completa\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n  dataUltimaMov DateTime? // Data da última movimentação\n\n  @@unique([insumoId, localizacaoId, lojaId]) // Evitar duplicatas\n  // Índices críticos para performance otimizada\n  @@index([lojaId])\n  @@index([insumoId, lojaId])\n  @@index([localizacaoId])\n  @@index([quantidadeAtual]) // Para consultas de estoque baixo\n  @@map(\"estoque_itens\")\n}\n\nmodel EstoqueMovimentacao {\n  id String @id @default(uuid())\n\n  // FK para estoque\n  estoqueId String\n  estoque   EstoqueItem @relation(fields: [estoqueId], references: [id])\n\n  // Dados da movimentação (logs completos e rastreáveis)\n  tipo                TipoMovimentacao\n  quantidade          Decimal\n  quantidadeAnterior  Decimal // Para auditoria\n  quantidadePosterior Decimal // Para auditoria\n\n  // Referências externas (opcionais para rastreabilidade)\n  documentoRef String? // NF, OS, etc\n  orcamentoId  String? // FK externa para orçamentos\n  usuarioId    String // FK externa para usuários (auditoria)\n\n  // Multi-tenant obrigatório (isolamento por loja)\n  lojaId String\n\n  // Timestamps e observações para logs completos\n  dataMovimentacao DateTime @default(now())\n  observacoes      String? // Observações da movimentação\n\n  // Índices para performance e consultas otimizadas\n  @@index([lojaId])\n  @@index([estoqueId])\n  @@index([dataMovimentacao])\n  @@index([tipo, lojaId])\n  @@index([usuarioId]) // Para auditoria por usuário\n  @@map(\"estoque_movimentacoes\")\n}\n\nmodel EstoqueLote {\n  id String @id @default(uuid())\n\n  // FK para estoque\n  estoqueId String\n  estoque   EstoqueItem @relation(fields: [estoqueId], references: [id])\n\n  // Dados do lote (controle de validade conforme premissas)\n  numeroLote     String\n  dataFabricacao DateTime?\n  dataValidade   DateTime? // Controle de validade\n  quantidadeLote Decimal\n  status         StatusLote @default(ATIVO)\n\n  // Multi-tenant obrigatório (isolamento por loja)\n  lojaId String\n\n  // Timestamps para auditoria\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Índices para performance\n  @@index([lojaId])\n  @@index([estoqueId])\n  @@index([dataValidade]) // Para relatórios de vencimento\n  @@index([status, lojaId])\n  @@index([numeroLote, lojaId])\n  @@map(\"estoque_lotes\")\n}\n\nmodel EstoqueSobra {\n  id String @id @default(uuid())\n\n  // FK para estoque (origem da sobra)\n  estoqueId String\n  estoque   EstoqueItem @relation(fields: [estoqueId], references: [id])\n\n  // Dados da sobra (específico do setor de comunicação visual)\n  codigoSobra   String      @unique // Código único da sobra (ex: SOB-2024-001)\n  descricao     String      @estoqueDb.Text // Descrição detalhada da sobra\n  dimensoes     String? // Dimensões (ex: \"100x50cm\", \"2mx1m\")\n  area          Decimal? // Área em m² (para cálculos de aproveitamento)\n  quantidade    Decimal // Quantidade disponível\n  unidadeMedida String // Unidade de medida (m², m, un, etc)\n  material      String // Tipo de material (PVC, adesivo, tecido, etc)\n  cor           String? // Cor do material\n  acabamento    String? // Acabamento (laminado, fosco, etc)\n  status        StatusSobra @default(DISPONIVEL)\n\n  // Dados de origem (rastreabilidade)\n  origem          String? // Origem da sobra (projeto, cliente, etc)\n  dataGeracao     DateTime @default(now()) // Data de geração da sobra\n  orcamentoOrigem String? // Referência ao orçamento que gerou a sobra\n\n  // Dados de aproveitamento\n  dataAproveitamento    DateTime? // Data do último aproveitamento\n  quantidadeAproveitada Decimal   @default(0) // Quantidade já aproveitada\n  economiaGerada        Decimal   @default(0) // Economia gerada em R$\n\n  // Multi-tenant obrigatório (isolamento por loja)\n  lojaId String\n\n  // Relacionamentos\n  aproveitamentos EstoqueAproveitamento[]\n\n  // Timestamps para auditoria\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Índices para performance e consultas\n  @@index([lojaId])\n  @@index([estoqueId])\n  @@index([status, lojaId])\n  @@index([material, lojaId])\n  @@index([dataGeracao])\n  @@index([codigoSobra, lojaId])\n  @@map(\"estoque_sobras\")\n}\n\nmodel EstoqueAproveitamento {\n  id String @id @default(uuid())\n\n  // FK para sobra\n  sobraId String\n  sobra   EstoqueSobra @relation(fields: [sobraId], references: [id])\n\n  // Dados do aproveitamento\n  quantidadeAproveitada Decimal\n  projetoDestino        String? // Projeto onde foi aproveitado\n  orcamentoDestino      String? // Orçamento de destino\n  observacoes           String? @estoqueDb.Text\n\n  // Multi-tenant obrigatório (isolamento por loja)\n  lojaId String\n\n  // Timestamps para auditoria\n  createdAt DateTime @default(now())\n\n  // Índices para performance\n  @@index([lojaId])\n  @@index([sobraId])\n  @@index([projetoDestino])\n  @@map(\"estoque_aproveitamentos\")\n}\n\n// ===== ENUMS =====\n\nenum TipoMovimentacao {\n  ENTRADA // Entrada de mercadoria\n  SAIDA // Saída de mercadoria\n  AJUSTE // Ajuste de estoque\n  INVENTARIO // Inventário físico\n  TRANSFERENCIA // Transferência entre localizações\n}\n\nenum StatusLote {\n  ATIVO // Lote ativo\n  VENCIDO // Lote vencido\n  CONSUMIDO // Lote totalmente consumido\n  BLOQUEADO // Lote bloqueado para uso\n}\n\nenum StatusSobra {\n  DISPONIVEL // Sobra disponível para uso\n  APROVEITADA // Sobra totalmente aproveitada\n  VENCIDA // Sobra vencida (material deteriorado)\n  DESCARTADA // Sobra descartada\n  RESERVADA // Sobra reservada para projeto específico\n}\n",
